// All booker data + interaction logic: fetching/windowing cal.com availability,
// derived selection state, and the handlers the UI wires to the calendar.
export function useBooker({
  target,
  timezone,
}: UseBookerParams): UseBookerResult {
  const [meta, setMeta] = useState<BookerMeta | null>(null);
  const [slotsByDate, setSlotsByDate] = useState<Record<string, string[]>>({});
  const [error, setError] = useState<BookerError | null>(null);
  const [isPending, setIsPending] = useState(false);
  const [timeZone] = useState(
    () => Intl.DateTimeFormat().resolvedOptions().timeZone || "UTC",
  );
  const [locale] = useState(
    () => Intl.DateTimeFormat().resolvedOptions().locale || "en-US",
  );
  const [currentMonth, setCurrentMonth] = useState(() => new Date());
  const [selectedTimeZone, setSelectedTimeZone] = useState(
    timezone ?? timeZone,
  );
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(undefined);
  const [_selectedTime, setSelectedTime] = useState<string | null>(null);
  const [selectedDurationMinutes, setSelectedDurationMinutes] = useState(30);
  const [is24Hour, setIs24Hour] = useState(() => prefers24Hour(locale));
  const coveredMonthsRef = useRef<Set<string>>(new Set());
  const resolvedRef = useRef<{
    dynamic?: {
      orgId?: number;
      orgSlug?: string;
      usernames: string[];
    };
    eventTypeId: number | null;
    eventTypeSlug: string | null;
  }>({ eventTypeId: null, eventTypeSlug: null });
  const lastIdentityRef = useRef<string | null>(null);
  const lastTimeZoneRef = useRef<string | null>(null);
  const lastDurationRef = useRef<number | null>(null);
  const autoSelectedMonthRef = useRef<string | null>(null);
  const slotsByDateRef = useRef<Record<string, string[]>>({});
  const slotsCacheRef = useRef<Map<string, Record<string, string[]>>>(
    new Map(),
  );
  const minimumBookingNoticeRef = useRef(0);
  const hasMultiDurationOptionsRef = useRef(false);
  const selectedDateRef = useRef(selectedDate);
  selectedDateRef.current = selectedDate;
  const inFlightMonthsRef = useRef<Map<string, Promise<void>>>(new Map());
  const availabilityRequestVersionRef = useRef(0);

  const targetIdentity = useCallback((): string => {
    if (target.type === "user") {
      return `user:${target.username}:${target.eventSlug}:${target.orgId ?? ""}`;
    }
    if (target.type === "team") {
      return `team:${target.teamId}:${target.eventSlug}:${target.orgId ?? ""}`;
    }
    if (target.type === "dynamic") {
      return `dynamic:${target.usernames.join(",")}:${target.orgSlug ?? ""}:${target.orgId ?? ""}`;
    }
    return `link:${target.bookingUrl}`;
  }, [target]);

  const buildKey = useCallback(
    (month: Date) =>
      `${targetIdentity()}|${selectedTimeZone}|${selectedDurationMinutes}|${month.getFullYear()}-${month.getMonth()}`,
    [selectedDurationMinutes, selectedTimeZone, targetIdentity],
  );

  const slotsCacheKey = useCallback(
    () => `${targetIdentity()}|${selectedTimeZone}|${selectedDurationMinutes}`,
    [selectedDurationMinutes, selectedTimeZone, targetIdentity],
  );

  const restoreSlotsFromCache = useCallback(() => {
    const cached = slotsCacheRef.current.get(slotsCacheKey()) ?? {};
    slotsByDateRef.current = cached;
    setSlotsByDate(cached);
  }, [slotsCacheKey]);

  useLayoutEffect(() => {
    restoreSlotsFromCache();
  }, [restoreSlotsFromCache]);

  // Fetch a window of several months in a single request, anchored at `anchor`.
  const fetchWindow = useCallback(
    async (anchor: Date): Promise<void> => {
      const anchorKey = buildKey(anchor);

      if (coveredMonthsRef.current.has(anchorKey)) {
        return;
      }

      const existingRequest = inFlightMonthsRef.current.get(anchorKey);
      if (existingRequest) {
        await existingRequest;
        return;
      }

      const requestVersion = availabilityRequestVersionRef.current;
      const windowMonthKeys = Array.from(
        { length: WINDOW_MONTHS },
        (_, offset) =>
          buildKey(
            new Date(anchor.getFullYear(), anchor.getMonth() + offset, 1),
          ),
      );
      const request = (async () => {
        const durationMinutes =
          getDynamicContext(target) || hasMultiDurationOptionsRef.current
            ? selectedDurationMinutes
            : undefined;

        const result = await fetchRawBookerDataAction({
          durationMinutes,
          fetchMeta: resolvedRef.current.eventTypeId == null,
          monthIso: anchor.toISOString(),
          monthsToFetch: WINDOW_MONTHS,
          target,
          timeZone: selectedTimeZone,
          eventTypeId: resolvedRef.current.eventTypeId ?? undefined,
        });

        if (!result.ok) {
          throw new BookerDataError(
            result.error,
            result.errorCode ?? "UNKNOWN",
          );
        }

        if (availabilityRequestVersionRef.current !== requestVersion) {
          return;
        }

        resolvedRef.current = result.resolved;

        for (let offset = 0; offset < WINDOW_MONTHS; offset += 1) {
          const month = new Date(
            anchor.getFullYear(),
            anchor.getMonth() + offset,
            1,
          );
          coveredMonthsRef.current.add(buildKey(month));
        }

        // The host/event metadata only comes back on the full (non slots-only)
        // fetch, so set it once when present.
        if (result.raw.me) {
          const host = extractHost(result.raw.me);
          const isDynamic = Boolean(getDynamicContext(target));
          const hostAvatars = extractHostAvatars(
            result.raw.selectedEventType,
            result.raw.me,
            { dynamic: isDynamic, orgSlug: getOrgSlugFromTarget(target) },
          );
          const hostName = extractHostDisplayName(
            result.raw.selectedEventType,
            result.raw.me,
            { dynamic: isDynamic },
          );
          const eventType = extractEventTypeInfo(result.raw.selectedEventType);
          minimumBookingNoticeRef.current = extractMinimumBookingNotice(
            result.raw.selectedEventType,
          );
          hasMultiDurationOptionsRef.current =
            (eventType.eventTypeDurationOptions?.length ?? 0) > 1;
          setMeta(
            (prev) =>
              prev ?? {
                hostName:
                  host.hostName === "Unknown user" && target.type === "user"
                    ? target.username
                    : result.raw.publicDisplayName || hostName,
                hostAvatarUrl: host.hostAvatarUrl,
                hostAvatars,
                eventTypeTitle: eventType.eventTypeTitle,
                eventTypeDescription: eventType.eventTypeDescription,
                eventTypeDurationMinutes: eventType.eventTypeDurationMinutes,
                eventTypeDurationOptions: eventType.eventTypeDurationOptions,
                eventTypeLocations: eventType.eventTypeLocations,
                eventTypeImageUrl:
                  result.raw.bannerUrl || eventType.eventTypeImageUrl,
                bookingWindowStart: extractBookingWindowStart(
                  result.raw.selectedEventType,
                ),
                bookingWindowEnd: extractBookingWindowEnd(
                  result.raw.selectedEventType,
                ),
              },
          );

          const defaultDuration =
            eventType.eventTypeDurationMinutes ??
            eventType.eventTypeDurationOptions?.[0] ??
            30;
          if (eventType.eventTypeDurationOptions?.length) {
            if (
              !eventType.eventTypeDurationOptions.includes(
                selectedDurationMinutes,
              )
            ) {
              setSelectedDurationMinutes(defaultDuration);
            }
          } else if (
            eventType.eventTypeDurationMinutes != null &&
            selectedDurationMinutes !== eventType.eventTypeDurationMinutes
          ) {
            setSelectedDurationMinutes(eventType.eventTypeDurationMinutes);
          }
        }

        const windowSlots = filterBookableSlots(
          extractSlotsByDate(result.raw.slots, selectedTimeZone),
          selectedTimeZone,
          minimumBookingNoticeRef.current,
          new Date(),
        );
        const cacheKey = `${targetIdentity()}|${selectedTimeZone}|${selectedDurationMinutes}`;
        const mergedSlots = {
          ...(slotsCacheRef.current.get(cacheKey) ?? {}),
          ...windowSlots,
        };
        slotsCacheRef.current.set(cacheKey, mergedSlots);
        slotsByDateRef.current = mergedSlots;
        setSlotsByDate(mergedSlots);
      })();

      for (const monthKey of windowMonthKeys) {
        inFlightMonthsRef.current.set(monthKey, request);
      }

      try {
        await request;
      } finally {
        for (const monthKey of windowMonthKeys) {
          if (inFlightMonthsRef.current.get(monthKey) === request) {
            inFlightMonthsRef.current.delete(monthKey);
          }
        }
      }
    },
    [
      buildKey,
      selectedDurationMinutes,
      selectedTimeZone,
      target,
      targetIdentity,
    ],
  );

  const todayStart = useMemo(
    () => getTodayInTimeZone(selectedTimeZone),
    [selectedTimeZone],
  );
  const startMonth = useMemo(
    () => getMinimumNavigableMonth(selectedTimeZone, meta?.bookingWindowStart),
    [meta?.bookingWindowStart, selectedTimeZone],
  );
  const calendarViewOptions = useMemo((): CalendarViewOptions => {
    return {
      endMonth: meta?.bookingWindowEnd ?? undefined,
      shiftWeeks: true,
      startMonth,
      weekStartsOn: getWeekStartsOn(locale),
    };
  }, [locale, meta?.bookingWindowEnd, startMonth]);

  const hasAvailabilityInView = useMemo(
    () =>
      hasAvailabilityInVisibleGrid(
        currentMonth,
        slotsByDate,
        todayStart,
        calendarViewOptions,
      ),
    [calendarViewOptions, currentMonth, slotsByDate, todayStart],
  );

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      const identity = targetIdentity();
      let deferLoadForMonthSync = false;

      // A different user/event means a different event type and metadata, so
      // reset everything and force a full fetch.
      if (
        lastIdentityRef.current !== null &&
        lastIdentityRef.current !== identity
      ) {
        coveredMonthsRef.current = new Set();
        inFlightMonthsRef.current.clear();
        availabilityRequestVersionRef.current += 1;
        resolvedRef.current = { eventTypeId: null, eventTypeSlug: null };
        hasMultiDurationOptionsRef.current = false;
        slotsCacheRef.current = new Map();
        slotsByDateRef.current = {};
        autoSelectedMonthRef.current = null;
        setMeta(null);
        setSelectedDurationMinutes(30);
        setSlotsByDate({});
      } else if (
        lastDurationRef.current !== null &&
        lastDurationRef.current !== selectedDurationMinutes
      ) {
        inFlightMonthsRef.current.clear();
        availabilityRequestVersionRef.current += 1;
        restoreSlotsFromCache();
        autoSelectedMonthRef.current = null;
        setSelectedTime(null);
      } else if (
        lastTimeZoneRef.current !== null &&
        lastTimeZoneRef.current !== selectedTimeZone
      ) {
        coveredMonthsRef.current = new Set();
        inFlightMonthsRef.current.clear();
        availabilityRequestVersionRef.current += 1;
        restoreSlotsFromCache();
        autoSelectedMonthRef.current = null;
        setSelectedTime(null);

        const minMonth = getMinimumNavigableMonth(
          selectedTimeZone,
          meta?.bookingWindowStart,
        );
        if (isCalendarMonthBefore(currentMonth, minMonth)) {
          setCurrentMonth(minMonth);
          deferLoadForMonthSync = true;
        } else {
          const todayInTz = getTodayInTimeZone(selectedTimeZone);
          if (
            selectedDateRef.current &&
            toCalendarDateKey(selectedDateRef.current) <
              toCalendarDateKey(todayInTz)
          ) {
            setSelectedDate(undefined);
          }
        }
      }
      lastIdentityRef.current = identity;
      lastTimeZoneRef.current = selectedTimeZone;
      lastDurationRef.current = selectedDurationMinutes;

      if (deferLoadForMonthSync) {
        return;
      }

      if (!coveredMonthsRef.current.has(buildKey(currentMonth))) {
        setIsPending(true);
        try {
          await fetchWindow(currentMonth);
          if (cancelled) {
            return;
          }
          setError(null);
        } catch (caught) {
          if (cancelled) {
            return;
          }
          setError(classifyError(caught));
          return;
        } finally {
          if (!cancelled) {
            setIsPending(false);
          }
        }
      } else {
        setError(null);
        setIsPending(false);
      }

      // Auto-select the first available day the first time this month's
      // availability is known (on load and on month navigation).
      const monthKey = `${currentMonth.getFullYear()}-${currentMonth.getMonth()}`;
      if (!cancelled && autoSelectedMonthRef.current !== monthKey) {
        const firstAvailable = pickDefaultSelectedDate(
          currentMonth,
          slotsByDateRef.current,
          selectedTimeZone,
          getTodayInTimeZone(selectedTimeZone),
          calendarViewOptions,
        );
        if (firstAvailable) {
          autoSelectedMonthRef.current = monthKey;
          setSelectedDate(firstAvailable);
          setSelectedTime(null);
        } else {
          autoSelectedMonthRef.current = monthKey;
          setSelectedDate(undefined);
          setSelectedTime(null);
        }
      }

      // Warm the next uncovered window boundary, not just the adjacent month.
      // This keeps navigation instant when the user reaches the end of the
      // currently-covered 3-month range.
      const nextWindow = new Date(
        currentMonth.getFullYear(),
        currentMonth.getMonth() + WINDOW_MONTHS,
        1,
      );
      if (!coveredMonthsRef.current.has(buildKey(nextWindow))) {
        void fetchWindow(nextWindow).catch(() => {});
      }
    };

    void load();

    return () => {
      cancelled = true;
    };
  }, [
    buildKey,
    currentMonth,
    fetchWindow,
    selectedDurationMinutes,
    selectedTimeZone,
    meta?.bookingWindowStart,
    calendarViewOptions,
    restoreSlotsFromCache,
    targetIdentity,
  ]);

  const [retryCounter, setRetryCounter] = useState(0);

  const retry = useCallback(() => {
    coveredMonthsRef.current = new Set();
    inFlightMonthsRef.current.clear();
    availabilityRequestVersionRef.current += 1;
    slotsCacheRef.current = new Map();
    slotsByDateRef.current = {};
    autoSelectedMonthRef.current = null;
    setSlotsByDate({});
    setError(null);
    setRetryCounter((c) => c + 1);
  }, []);

  // Re-trigger the main load effect when the user retries.
  useEffect(() => {
    // The first render (retryCounter === 0) is handled by the main effect.
    if (retryCounter === 0) return;
    setIsPending(true);
    let cancelled = false;

    (async () => {
      try {
        await fetchWindow(currentMonth);
        if (cancelled) return;
        setError(null);

        const monthKey = `${currentMonth.getFullYear()}-${currentMonth.getMonth()}`;
        if (autoSelectedMonthRef.current !== monthKey) {
          const firstAvailable = pickDefaultSelectedDate(
            currentMonth,
            slotsByDateRef.current,
            selectedTimeZone,
            getTodayInTimeZone(selectedTimeZone),
            calendarViewOptions,
          );
          if (firstAvailable) {
            autoSelectedMonthRef.current = monthKey;
            setSelectedDate(firstAvailable);
            setSelectedTime(null);
          } else {
            autoSelectedMonthRef.current = monthKey;
            setSelectedDate(undefined);
            setSelectedTime(null);
          }
        }
      } catch (caught) {
        if (cancelled) return;
        setError(classifyError(caught));
      } finally {
        if (!cancelled) setIsPending(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [
    retryCounter,
    fetchWindow,
    currentMonth,
    selectedTimeZone,
    calendarViewOptions,
  ]);

  useEffect(() => {
    if (!timezone) {
      return;
    }
    setSelectedTimeZone(timezone);
  }, [timezone]);

  const selectedDateKey = toCalendarDateKey(selectedDate ?? todayStart);
  const daySlots =
    selectedDate != null ? (slotsByDate[selectedDateKey] ?? []) : [];
  const nextAvailableDate = findNextAvailableDate(
    slotsByDate,
    selectedTimeZone,
    todayStart,
  );

  const handleMonthChange = (month: Date) => {
    const monthKey = `${month.getFullYear()}-${month.getMonth()}`;
    const monthCovered = coveredMonthsRef.current.has(buildKey(month));
    setCurrentMonth(month);
    // Flip to pending in the same render as the month change when the target
    // month still needs fetching, so the skeleton shows immediately instead of
    // the empty state flashing for a frame before the async effect runs.
    if (!monthCovered) {
      setIsPending(true);
    }
    // For an already-loaded month, select the first available day in the same
    // update as the month change so the selection doesn't flicker.
    const firstAvailable = pickDefaultSelectedDate(
      month,
      slotsByDateRef.current,
      selectedTimeZone,
      getTodayInTimeZone(selectedTimeZone),
      calendarViewOptions,
    );
    if (firstAvailable) {
      autoSelectedMonthRef.current = monthKey;
      setSelectedDate(firstAvailable);
      setSelectedTime(null);
    } else {
      if (monthCovered) {
        autoSelectedMonthRef.current = monthKey;
      }
      setSelectedDate(undefined);
      setSelectedTime(null);
    }
  };

  const handleSelectDate = (nextDate: Date | undefined) => {
    if (!nextDate) {
      return;
    }
    setSelectedDate(nextDate);
    setSelectedTime(null);
    autoSelectedMonthRef.current = `${nextDate.getFullYear()}-${nextDate.getMonth()}`;
    const isDifferentMonth =
      nextDate.getMonth() !== currentMonth.getMonth() ||
      nextDate.getFullYear() !== currentMonth.getFullYear();
    if (isDifferentMonth) {
      setCurrentMonth(nextDate);
    }
  };

  const isDayDisabled = (date: Date) => {
    const dayKey = toCalendarDateKey(date);
    if (dayKey < toCalendarDateKey(todayStart)) {
      return true;
    }

    return (slotsByDate[dayKey] ?? []).length === 0;
  };

  const goToDate = (date: Date) => {
    setCurrentMonth(date);
    setSelectedDate(date);
    setSelectedTime(null);
    autoSelectedMonthRef.current = `${date.getFullYear()}-${date.getMonth()}`;
  };

  const initialLoading = !meta;
  const availabilityLoading = isPending;

  return {
    calendarProps: {
      availabilityLoading,
      disabled: isDayDisabled,
      endMonth: meta?.bookingWindowEnd ?? undefined,
      initialLoading,
      locale,
      month: currentMonth,
      onMonthChange: handleMonthChange,
      onSelect: handleSelectDate,
      selected: selectedDate,
      startMonth,
      today: todayStart,
    },
    durationProps: {
      onValueChange: setSelectedDurationMinutes,
      value: selectedDurationMinutes,
    },
    error,
    loadingState: {
      availability: availabilityLoading,
      busy: initialLoading || availabilityLoading,
      initial: initialLoading,
    },
    meta,
    retry,
    timePickerProps: {
      availabilityLoading,
      currentMonth,
      daySlots,
      goToDate,
      hasAvailabilityInView,
      initialLoading,
      is24Hour,
      locale,
      nextAvailableDate,
      onIs24HourChange: setIs24Hour,
      onSelectTime: setSelectedTime,
      selectedDate,
    },
    timezoneProps: {
      onValueChange: setSelectedTimeZone,
      value: selectedTimeZone,
    },
  };
}

export type DynamicTargetContext = {
  usernames: string[];
  orgId?: number;
  orgSlug?: string;
};

export type BookerTarget =
  | {
      type: "user";
      username: string;
      eventSlug: string;
      orgId?: number;
    }
  | {
      type: "team";
      teamId: number;
      eventSlug: string;
      orgId?: number;
    }
  | {
      type: "dynamic";
      usernames: string[];
      orgId?: number;
      orgSlug?: string;
    }
  | {
      type: "link";
      bookingUrl: string;
      orgId?: number;
    };

export type LegacyBookerTargetInput = {
  username?: string | string[];
  eventSlug?: string;
  isTeamEvent?: boolean;
  teamId?: number;
  bookingUrl?: string;
  orgId?: number;
};

export type ParsedLinkTarget =
  | {
      type: "user";
      username: string;
      eventSlug: string;
      orgId?: number;
      orgSlug?: string;
    }
  | {
      type: "dynamic";
      usernames: string[];
      orgId?: number;
      orgSlug?: string;
    }
  | {
      type: "teamSlug";
      teamSlug: string;
      eventSlug: string;
      orgId?: number;
      orgSlug?: string;
    };

const DYNAMIC_EVENT_SLUG = "dynamic";

function parsePositiveInt(value: string | null): number | undefined {
  if (!value) {
    return undefined;
  }

  const parsed = Number(value);
  return Number.isInteger(parsed) && parsed > 0 ? parsed : undefined;
}

function toUrl(value: string): URL {
  const trimmed = value.trim();
  if (!trimmed) {
    throw new Error("Pass a non-empty bookingUrl.");
  }

  if (/^https?:\/\//i.test(trimmed)) {
    return new URL(trimmed);
  }

  return new URL(`https://${trimmed}`);
}

function parseOrgSlugFromHostname(hostname: string): string | undefined {
  const match = hostname.match(/^([a-z0-9-]+)\.cal\.com$/i);
  const subdomain = match?.[1]?.toLowerCase();

  if (!subdomain) {
    return undefined;
  }

  if (["api", "app", "cal", "www"].includes(subdomain)) {
    return undefined;
  }

  return subdomain;
}

function parseDynamicUsernames(
  pathUsername: string,
  userParam: string | null,
): string[] {
  const source = userParam ?? decodeURIComponent(pathUsername);
  return source
    .split(/[+,\s]+/)
    .map((part) => part.trim())
    .filter(Boolean);
}

export function getOrgSlugFromTarget(target: BookerTarget): string | undefined {
  if (target.type === "dynamic") {
    return target.orgSlug;
  }

  if (target.type === "link") {
    return parseBookingUrlTarget(target.bookingUrl, target.orgId).orgSlug;
  }

  return undefined;
}

export function getUserSlotParamsFromTarget(
  target: BookerTarget,
): { username: string; eventTypeSlug: string } | null {
  if (target.type === "user") {
    return { eventTypeSlug: target.eventSlug, username: target.username };
  }

  if (target.type === "link") {
    const parsed = parseBookingUrlTarget(target.bookingUrl, target.orgId);
    if (parsed.type === "user") {
      return { eventTypeSlug: parsed.eventSlug, username: parsed.username };
    }
  }

  return null;
}

export function getPublicEventBannerParamsFromTarget(target: BookerTarget): {
  username: string;
  eventSlug: string;
  orgSlug: string;
  isTeamEvent?: boolean;
} | null {
  if (target.type !== "link") {
    return null;
  }

  const parsed = parseBookingUrlTarget(target.bookingUrl, target.orgId);
  if (!parsed.orgSlug) {
    return null;
  }

  if (parsed.type === "user") {
    return {
      eventSlug: parsed.eventSlug,
      orgSlug: parsed.orgSlug,
      username: parsed.username,
    };
  }

  if (parsed.type === "teamSlug") {
    return {
      eventSlug: parsed.eventSlug,
      isTeamEvent: true,
      orgSlug: parsed.orgSlug,
      username: parsed.teamSlug,
    };
  }

  if (parsed.type === "dynamic") {
    return {
      eventSlug: "dynamic",
      orgSlug: parsed.orgSlug,
      username: parsed.usernames.join("+"),
    };
  }

  return null;
}

export function getDynamicContext(
  target: BookerTarget,
): DynamicTargetContext | null {
  if (target.type === "dynamic") {
    return {
      orgId: target.orgId,
      orgSlug: target.orgSlug,
      usernames: target.usernames,
    };
  }

  if (target.type === "link") {
    const parsed = parseBookingUrlTarget(target.bookingUrl, target.orgId);
    if (parsed.type === "dynamic") {
      return {
        orgId: parsed.orgId,
        orgSlug: parsed.orgSlug,
        usernames: parsed.usernames,
      };
    }
  }

  return null;
}

export function parseBookingUrlTarget(
  bookingUrl: string,
  fallbackOrgId?: number,
): ParsedLinkTarget {
  const url = toUrl(bookingUrl);
  const parts = url.pathname.split("/").filter(Boolean);
  const orgId =
    parsePositiveInt(url.searchParams.get("orgId")) ?? fallbackOrgId;
  const orgSlug = parseOrgSlugFromHostname(url.hostname);

  if (parts.length < 2) {
    throw new Error(
      "bookingUrl must include at least username/team and eventSlug.",
    );
  }

  if (parts[0] === "team" && parts.length >= 3) {
    return {
      eventSlug: decodeURIComponent(parts[2] ?? ""),
      orgId,
      orgSlug,
      teamSlug: decodeURIComponent(parts[1] ?? ""),
      type: "teamSlug",
    };
  }

  const eventSlug = decodeURIComponent(parts[1] ?? "");
  const pathUsername = decodeURIComponent(parts[0] ?? "");

  if (eventSlug === DYNAMIC_EVENT_SLUG) {
    const usernames = parseDynamicUsernames(
      pathUsername,
      url.searchParams.get("user"),
    );
    if (usernames.length >= 2) {
      return { orgId, orgSlug, type: "dynamic", usernames };
    }
  }

  return {
    eventSlug,
    orgId,
    orgSlug,
    type: "user",
    username: pathUsername,
  };
}

export function normalizeLegacyTarget(
  props: LegacyBookerTargetInput,
): BookerTarget {
  if (props.bookingUrl) {
    return { bookingUrl: props.bookingUrl, orgId: props.orgId, type: "link" };
  }

  if (props.isTeamEvent) {
    if (!props.teamId || !props.eventSlug) {
      throw new Error(
        "For team events, pass teamId and eventSlug in target or legacy props.",
      );
    }

    return {
      eventSlug: props.eventSlug,
      orgId: props.orgId,
      teamId: props.teamId,
      type: "team",
    };
  }

  const username = Array.isArray(props.username)
    ? props.username.join("+")
    : props.username;
  if (!username || !props.eventSlug) {
    throw new Error("Pass target or username + eventSlug.");
  }

  return {
    eventSlug: props.eventSlug,
    orgId: props.orgId,
    type: "user",
    username,
  };
}

export type EventTypeLocationOption = {
  label: string;
  provider: string;
};

export type BookerAvatar = {
  name: string;
  avatarUrl: string;
  profileUrl: string;
};

export type BookerMeta = {
  hostName: string;
  hostAvatarUrl: string;
  hostAvatars: BookerAvatar[];
  eventTypeTitle: string;
  eventTypeDescription: string;
  eventTypeDurationMinutes: number | null;
  eventTypeDurationOptions: number[] | null;
  eventTypeLocations: EventTypeLocationOption[];
  eventTypeImageUrl: string;
  bookingWindowStart: Date | null;
  bookingWindowEnd: Date | null;
};

export type EventTypeInfo = {
  eventTypeTitle: string;
  eventTypeDescription: string;
  eventTypeDurationMinutes: number | null;
  eventTypeDurationOptions: number[] | null;
  eventTypeLocations: EventTypeLocationOption[];
  eventTypeImageUrl: string;
};

export function prettifyLocation(value: string): string {
  const normalized = value.trim().toLowerCase();

  const known: Record<string, string> = {
    "cal-video": "Cal Video",
    "daily-video": "Daily Video",
    "google-meet": "Google Meet",
    "huddle01-video": "Huddle01",
    "microsoft-teams": "Microsoft Teams",
    conferencing: "Organizer's Default App",
    jitsi: "Jitsi Meet",
    inperson: "In person",
    organizersdefaultapp: "Organizer's Default App",
    phone: "Phone call",
    whereby: "Whereby",
    zoom: "Zoom",
  };

  const knownLocation = known[normalized];
  if (knownLocation) {
    return knownLocation;
  }

  return titleizeLocation(value);
}

function titleizeLocation(value: string): string {
  return value
    .replace(/[_:-]+/g, " ")
    .split(" ")
    .filter(Boolean)
    .map((part) =>
      /^\d+$/.test(part) ? part : part.charAt(0).toUpperCase() + part.slice(1),
    )
    .join(" ");
}

function normalizeAvatarUrl(value: unknown): string {
  if (typeof value !== "string") {
    return "";
  }

  const trimmed = value.trim();
  if (!trimmed) {
    return "";
  }

  if (trimmed.startsWith("http://") || trimmed.startsWith("https://")) {
    return trimmed;
  }

  if (trimmed.startsWith("//")) {
    return `https:${trimmed}`;
  }

  if (trimmed.startsWith("/")) {
    return `https://app.cal.com${trimmed}`;
  }

  return trimmed;
}

export function extractHost(payload: unknown): {
  hostName: string;
  hostAvatarUrl: string;
} {
  if (!payload || typeof payload !== "object") {
    return { hostName: "Unknown user", hostAvatarUrl: "" };
  }

  const root = payload as Record<string, unknown>;
  const data = (root.data as Record<string, unknown> | undefined) ?? root;
  const profile =
    data.profile && typeof data.profile === "object"
      ? (data.profile as Record<string, unknown>)
      : undefined;

  const rawAvatar =
    data.avatarUrl ??
    data.avatar_url ??
    data.avatar ??
    profile?.avatarUrl ??
    profile?.avatar_url ??
    profile?.avatar;

  return {
    hostName: String(
      data.name ?? data.username ?? data.email ?? "Unknown user",
    ),
    hostAvatarUrl: normalizeAvatarUrl(rawAvatar),
  };
}

function toRecord(value: unknown): Record<string, unknown> | null {
  return value && typeof value === "object"
    ? (value as Record<string, unknown>)
    : null;
}

function getAvatarName(record: Record<string, unknown>): string {
  return String(
    record.name ?? record.username ?? record.email ?? "Unknown user",
  );
}

function getAvatarUrl(record: Record<string, unknown>): string {
  const profile = toRecord(record.profile);
  return normalizeAvatarUrl(
    record.avatarUrl ??
      record.avatar_url ??
      record.avatar ??
      record.image ??
      record.logoUrl ??
      profile?.avatarUrl ??
      profile?.avatar_url ??
      profile?.avatar ??
      profile?.image,
  );
}

function buildProfileUrl(
  username: string,
  orgSlug?: string,
  baseUrl?: string,
): string {
  const normalizedUsername = username.trim();
  if (!normalizedUsername) {
    return "";
  }

  const base =
    baseUrl && /^https?:\/\//i.test(baseUrl)
      ? baseUrl.replace(/\/$/, "")
      : orgSlug
        ? `https://${orgSlug}.cal.com`
        : "https://cal.com";

  return `${base}/${encodeURIComponent(normalizedUsername)}`;
}

function getUserAvatar(
  record: Record<string, unknown>,
  orgSlug?: string,
): BookerAvatar {
  const name = getAvatarName(record);
  const username = getStringValue(record.username);
  const bookerUrl = getStringValue(record.bookerUrl);

  return {
    avatarUrl: getAvatarUrl(record),
    name,
    profileUrl: username
      ? buildProfileUrl(username, orgSlug, bookerUrl ?? undefined)
      : "",
  };
}

function getTeamAvatar(
  record: Record<string, unknown>,
  orgSlug?: string,
): BookerAvatar | null {
  const team = toRecord(record.team) ?? toRecord(record.entity);
  const profile = toRecord(record.profile);
  const source = team ?? profile;
  if (!source) {
    return null;
  }

  const avatarUrl = getAvatarUrl(source);
  const name = String(source.name ?? source.slug ?? "");
  const slug = getStringValue(source.slug);
  if (!avatarUrl && !name) {
    return null;
  }

  return {
    avatarUrl,
    name: name || "Team",
    profileUrl: slug ? buildProfileUrl(slug, orgSlug) : "",
  };
}

function getBooleanValue(value: unknown): boolean {
  return value === true || value === "true";
}

function uniqueAvatars(avatars: BookerAvatar[]): BookerAvatar[] {
  const seen = new Set<string>();
  return avatars.filter((avatar) => {
    const key = `${avatar.name}:${avatar.avatarUrl}`;
    if (seen.has(key)) {
      return false;
    }
    seen.add(key);
    return true;
  });
}

export function extractHostAvatars(
  eventTypePayload: unknown,
  hostPayload: unknown,
  options: { dynamic?: boolean; orgSlug?: string } = {},
): BookerAvatar[] {
  const eventType = toRecord(eventTypePayload);
  const host = extractHost(hostPayload);

  if (!eventType) {
    return host.hostName === "Unknown user" && !host.hostAvatarUrl
      ? []
      : [
          {
            avatarUrl: host.hostAvatarUrl,
            name: host.hostName,
            profileUrl: "",
          },
        ];
  }

  const schedulingType = String(eventType.schedulingType ?? "").toUpperCase();
  const metadata = toRecord(eventType.metadata);
  const roundRobinHideOrgAndTeam =
    getBooleanValue(eventType.roundRobinHideOrgAndTeam) ||
    getBooleanValue(metadata?.roundRobinHideOrgAndTeam);
  const hideOrgTeamAvatar =
    getBooleanValue(eventType.hideOrgTeamAvatar) ||
    getBooleanValue(metadata?.hideOrgTeamAvatar);
  const userRecords = [
    ...(Array.isArray(eventType.users) ? eventType.users : []),
    ...(Array.isArray(eventType.hosts) ? eventType.hosts : []),
  ]
    .map(toRecord)
    .filter((record): record is Record<string, unknown> => record != null);
  const userAvatars = userRecords.map((record) =>
    getUserAvatar(record, options.orgSlug),
  );
  const teamAvatar = getTeamAvatar(eventType, options.orgSlug);

  if (options.dynamic) {
    return uniqueAvatars(
      userAvatars.length > 0
        ? userAvatars
        : [
            {
              avatarUrl: host.hostAvatarUrl,
              name: host.hostName,
              profileUrl: "",
            },
          ],
    );
  }

  if (schedulingType === "ROUND_ROBIN") {
    if (roundRobinHideOrgAndTeam || hideOrgTeamAvatar) {
      return [];
    }

    return teamAvatar ? [teamAvatar] : [];
  }

  if (schedulingType === "COLLECTIVE") {
    const avatars = teamAvatar ? [teamAvatar, ...userAvatars] : userAvatars;
    return uniqueAvatars(avatars);
  }

  const firstUserAvatar = userAvatars[0];
  return uniqueAvatars(
    firstUserAvatar
      ? [firstUserAvatar]
      : [
          {
            avatarUrl: host.hostAvatarUrl,
            name: host.hostName,
            profileUrl: "",
          },
        ],
  );
}

export function extractHostDisplayName(
  eventTypePayload: unknown,
  hostPayload: unknown,
  options: { dynamic?: boolean } = {},
): string {
  const host = extractHost(hostPayload);
  const eventType = toRecord(eventTypePayload);
  if (!eventType) {
    return host.hostName;
  }

  const schedulingType = String(eventType.schedulingType ?? "").toUpperCase();
  const profile = toRecord(eventType.profile);
  const team = toRecord(eventType.team) ?? toRecord(eventType.entity);
  const profileName =
    getStringValue(profile?.name) ?? getStringValue(team?.name);
  const userNames = [
    ...(Array.isArray(eventType.users) ? eventType.users : []),
    ...(Array.isArray(eventType.hosts) ? eventType.hosts : []),
  ]
    .map(toRecord)
    .filter((record): record is Record<string, unknown> => record != null)
    .map(getAvatarName)
    .filter((name) => name !== "Unknown user");

  if (options.dynamic) {
    return (
      profileName ??
      (userNames.length > 0 ? userNames.join(", ") : host.hostName)
    );
  }

  if (schedulingType === "ROUND_ROBIN") {
    return profileName ?? host.hostName;
  }

  if (schedulingType === "COLLECTIVE") {
    const firstName = userNames[0];
    if (profileName && firstName && profileName !== firstName) {
      return profileName;
    }

    return userNames.length > 0 ? userNames.join(", ") : host.hostName;
  }

  return host.hostName;
}

function parseLocationOption(value: unknown): EventTypeLocationOption | null {
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!trimmed) {
      return null;
    }

    return { label: prettifyLocation(trimmed), provider: "" };
  }

  if (!value || typeof value !== "object") {
    return null;
  }

  const loc = value as Record<string, unknown>;
  const integrationProvider = getIntegrationProvider(loc);
  const provider = integrationProvider || getStringValue(loc.type) || "";
  const rawText =
    getDisplayLocationText(loc.label, integrationProvider) ??
    getDisplayLocationText(loc.name, integrationProvider) ??
    (integrationProvider || null) ??
    getStringValue(loc.address) ??
    getStringValue(loc.location) ??
    getStringValue(loc.value) ??
    getStringValue(loc.type);

  if (!rawText) {
    return null;
  }

  return {
    label: prettifyLocation(rawText),
    provider,
  };
}

function extractLocations(
  record: Record<string, unknown>,
): EventTypeLocationOption[] {
  const locationsRaw = record.locations;
  if (Array.isArray(locationsRaw) && locationsRaw.length > 0) {
    const parsed = locationsRaw
      .map(parseLocationOption)
      .filter((item): item is EventTypeLocationOption => item != null);
    if (parsed.length > 0) {
      return parsed;
    }
  }

  if (typeof record.location === "string" && record.location.trim()) {
    return [{ label: prettifyLocation(record.location), provider: "" }];
  }

  return [{ label: "Unknown", provider: "" }];
}

export function extractEventTypeInfo(payload: unknown): EventTypeInfo {
  if (!payload || typeof payload !== "object") {
    return {
      eventTypeTitle: "No event type found",
      eventTypeDescription: "",
      eventTypeDurationMinutes: null,
      eventTypeDurationOptions: null,
      eventTypeLocations: [{ label: "Unknown", provider: "" }],
      eventTypeImageUrl: "",
    };
  }

  const record = payload as Record<string, unknown>;
  const durationValue =
    record.lengthInMinutes ??
    record.duration ??
    record.length ??
    record.minutes;
  const duration =
    typeof durationValue === "number"
      ? durationValue
      : typeof durationValue === "string" &&
          Number.isFinite(Number(durationValue))
        ? Number(durationValue)
        : null;

  const durationOptions = extractDurationOptions(record);
  const eventTypeLocations = extractLocations(record);

  return {
    eventTypeTitle: String(
      record.title ?? record.name ?? record.slug ?? "No event type found",
    ),
    eventTypeDescription: String(record.description ?? ""),
    eventTypeDurationMinutes: duration,
    eventTypeDurationOptions:
      durationOptions.length > 1 ? durationOptions : null,
    eventTypeLocations,
    eventTypeImageUrl: normalizeAvatarUrl(
      record.imageUrl ??
        record.image_url ??
        record.image ??
        record.bannerUrl ??
        record.coverImage ??
        record.coverImageUrl,
    ),
  };
}

function getStringValue(value: unknown): string | null {
  return typeof value === "string" && value.trim() ? value : null;
}

function getDisplayLocationText(
  value: unknown,
  integrationProvider: string,
): string | null {
  const text = getStringValue(value);
  if (!text) {
    return null;
  }

  const normalized = text.trim().toLowerCase();
  if (
    integrationProvider &&
    ["integration", "integrations"].includes(normalized)
  ) {
    return null;
  }

  return text;
}

function getIntegrationProvider(record: Record<string, unknown>): string {
  const rawType = getStringValue(record.type);
  const type = rawType?.trim().toLowerCase();
  const candidates = [
    record.value,
    record.integration,
    record.provider,
    record.app,
    record.appSlug,
    record.credentialType,
  ];
  for (const candidate of candidates) {
    const value = getStringValue(candidate);
    if (!value) {
      continue;
    }
    const normalized = value.trim().toLowerCase();
    if (
      ["integration", "integrations"].includes(type ?? "") &&
      !["integration", "integrations"].includes(normalized) &&
      /^[a-z0-9][a-z0-9:_-]*$/i.test(value)
    ) {
      return value;
    }
  }
  return "";
}

function toFiniteNumber(value: unknown): number | null {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  if (
    typeof value === "string" &&
    value.trim() !== "" &&
    Number.isFinite(Number(value))
  ) {
    return Number(value);
  }
  return null;
}

function normalizeDurationList(values: unknown[]): number[] {
  const minutes = values
    .map(toFiniteNumber)
    .filter((value): value is number => value != null && value > 0);

  return [...new Set(minutes)].sort((a, b) => a - b);
}

export function extractDurationOptions(payload: unknown): number[] {
  if (!payload || typeof payload !== "object") {
    return [];
  }

  const record = payload as Record<string, unknown>;
  const fromOptions = record.lengthInMinutesOptions;
  if (Array.isArray(fromOptions)) {
    const normalized = normalizeDurationList(fromOptions);
    if (normalized.length > 0) {
      return normalized;
    }
  }

  const metadata = record.metadata;
  if (metadata && typeof metadata === "object") {
    const multipleDuration = (metadata as Record<string, unknown>)
      .multipleDuration;
    if (Array.isArray(multipleDuration)) {
      return normalizeDurationList(multipleDuration);
    }
  }

  return [];
}

function addCalendarDays(date: Date, days: number): Date {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate() + days);
}

function addBusinessDays(date: Date, days: number): Date {
  const result = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  let remaining = Math.max(0, days);
  while (remaining > 0) {
    result.setDate(result.getDate() + 1);
    const dayOfWeek = result.getDay();
    if (dayOfWeek !== 0 && dayOfWeek !== 6) {
      remaining -= 1;
    }
  }
  return result;
}

function parseDate(value: unknown): Date | null {
  if (typeof value !== "string" && typeof value !== "number") {
    return null;
  }
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

// Resolve the event type's booking window start date. For RANGE period types,
// this is the `periodStartDate`; otherwise bookings start from today.
export function extractBookingWindowStart(payload: unknown): Date | null {
  if (!payload || typeof payload !== "object") {
    return null;
  }

  const eventType = payload as Record<string, unknown>;
  const periodType =
    typeof eventType.periodType === "string"
      ? eventType.periodType.toUpperCase()
      : "";

  if (periodType === "RANGE") {
    const start = parseDate(eventType.periodStartDate);
    if (start) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      // Never return a start date in the past.
      return start > today ? start : null;
    }
  }

  return null;
}

export function extractBookingWindowEnd(payload: unknown): Date | null {
  if (!payload || typeof payload !== "object") {
    return null;
  }

  const eventType = payload as Record<string, unknown>;
  const periodType =
    typeof eventType.periodType === "string"
      ? eventType.periodType.toUpperCase()
      : "";

  if (periodType === "RANGE") {
    return parseDate(eventType.periodEndDate);
  }

  if (periodType === "ROLLING" || periodType === "ROLLING_WINDOW") {
    const days = toFiniteNumber(eventType.periodDays);
    if (days != null) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      return eventType.periodCountCalendarDays
        ? addCalendarDays(today, days)
        : addBusinessDays(today, days);
    }
  }

  return null;
}

export function getInitials(name: string): string {
  const parts = name
    .split(" ")
    .map((part) => part.trim())
    .filter(Boolean)
    .slice(0, 2);

  if (parts.length === 0) {
    return "NA";
  }

  return parts.map((part) => part[0]?.toUpperCase() ?? "").join("");
}

export function formatSelectedWeekday(date: Date, locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    weekday: "short",
  }).format(date);
}

export function formatSelectedDay(date: Date, locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    day: "2-digit",
  }).format(date);
}

export function formatSelectedMonth(date: Date, locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    month: "short",
  }).format(date);
}

export function toDateKey(date: Date, timeZone: string): string {
  return new Intl.DateTimeFormat("en-CA", {
    day: "2-digit",
    month: "2-digit",
    timeZone,
    year: "numeric",
  }).format(date);
}

// Calendar grid dates are plain Y-M-D values (local Date components), not
// instants. Use this when looking up slots keyed by the API/booking timezone.
export function toCalendarDateKey(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

export function getTodayInTimeZone(
  timeZone: string,
  now: Date = new Date(),
): Date {
  const [yearRaw, monthRaw, dayRaw] = toDateKey(now, timeZone).split("-");
  const year = Number(yearRaw);
  const month = Number(monthRaw);
  const day = Number(dayRaw);
  if (Number.isNaN(year) || Number.isNaN(month) || Number.isNaN(day)) {
    const fallback = new Date(now);
    fallback.setHours(0, 0, 0, 0);
    return fallback;
  }
  return new Date(year, month - 1, day);
}

export function getMinimumNavigableMonth(
  timeZone: string,
  bookingWindowStart?: Date | null,
  now: Date = new Date(),
): Date {
  const todayInTz = getTodayInTimeZone(timeZone, now);
  const startBase =
    bookingWindowStart && bookingWindowStart > todayInTz
      ? bookingWindowStart
      : todayInTz;
  return new Date(startBase.getFullYear(), startBase.getMonth(), 1);
}

export function isCalendarMonthBefore(left: Date, right: Date): boolean {
  const leftMonth = new Date(left.getFullYear(), left.getMonth(), 1);
  const rightMonth = new Date(right.getFullYear(), right.getMonth(), 1);
  return leftMonth.getTime() < rightMonth.getTime();
}

function toTimeLabel(date: Date, timeZone: string): string {
  return new Intl.DateTimeFormat("en-GB", {
    hour: "2-digit",
    hour12: false,
    minute: "2-digit",
    timeZone,
  }).format(date);
}

// Whether a locale conventionally shows time in 24-hour form, used to seed the
// 12h/24h toggle (e.g. en-US → 12h, most of Europe → 24h). Falls back to 24h.
export function prefers24Hour(locale: string): boolean {
  try {
    const resolved = new Intl.DateTimeFormat(locale, {
      hour: "numeric",
    }).resolvedOptions();
    if (typeof resolved.hour12 === "boolean") {
      return !resolved.hour12;
    }
    return resolved.hourCycle === "h23" || resolved.hourCycle === "h24";
  } catch {
    return true;
  }
}

// Slots are stored as 24h "HH:mm" strings (stable ids); reformat for display.
export function displayTimeLabel(label: string, hour12: boolean): string {
  if (!hour12) {
    return label;
  }
  const [hoursRaw, minutesRaw] = label.split(":");
  const hours = Number(hoursRaw);
  const minutes = Number(minutesRaw);
  if (Number.isNaN(hours) || Number.isNaN(minutes)) {
    return label;
  }
  const date = new Date();
  date.setHours(hours, minutes, 0, 0);
  const parts = new Intl.DateTimeFormat(undefined, {
    hour: "numeric",
    hour12: true,
    minute: "2-digit",
  }).formatToParts(date);
  return parts
    .filter((part) => part.type !== "literal" || part.value.trim() !== "")
    .map((part) =>
      part.type === "dayPeriod" ? part.value.toLowerCase() : part.value,
    )
    .join("");
}

export function isSingleDigit12HourLabel(label: string): boolean {
  const hours = Number(label.split(":")[0]);
  if (Number.isNaN(hours)) {
    return false;
  }

  const normalizedHours = hours % 12 || 12;
  return normalizedHours < 10;
}

function parseSlotDate(value: unknown): Date | null {
  if (typeof value === "string") {
    if (/^\d{2}:\d{2}$/.test(value)) {
      return null;
    }
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? null : parsed;
  }

  if (!value || typeof value !== "object") {
    return null;
  }

  const record = value as Record<string, unknown>;
  const candidate =
    record.start ??
    record.startTime ??
    record.time ??
    record.dateTime ??
    record.date;

  return parseSlotDate(candidate);
}

export function extractSlotsByDate(
  payload: unknown,
  timeZone: string,
): Record<string, string[]> {
  const byDate = new Map<string, Set<string>>();
  const addSlot = (dateKey: string, time: string) => {
    if (!byDate.has(dateKey)) {
      byDate.set(dateKey, new Set<string>());
    }
    byDate.get(dateKey)?.add(time);
  };

  if (!payload || typeof payload !== "object") {
    return {};
  }

  const visitNode = (node: unknown) => {
    if (!node || typeof node !== "object") {
      return;
    }

    if (Array.isArray(node)) {
      for (const item of node) {
        visitNode(item);
      }
      return;
    }

    const record = node as Record<string, unknown>;

    for (const [key, value] of Object.entries(record)) {
      if (/^\d{4}-\d{2}-\d{2}$/.test(key) && Array.isArray(value)) {
        for (const slot of value) {
          if (typeof slot === "string" && /^\d{2}:\d{2}$/.test(slot)) {
            addSlot(key, slot);
            continue;
          }

          const parsed = parseSlotDate(slot);
          if (!parsed) {
            continue;
          }

          addSlot(toDateKey(parsed, timeZone), toTimeLabel(parsed, timeZone));
        }
      } else {
        visitNode(value);
      }
    }
  };

  visitNode(payload);

  const result: Record<string, string[]> = {};
  for (const [key, times] of byDate.entries()) {
    result[key] = Array.from(times).sort((a, b) => a.localeCompare(b));
  }

  return result;
}

// Event's minimum booking notice in minutes (cal.com `minimumBookingNotice`).
export function extractMinimumBookingNotice(payload: unknown): number {
  if (!payload || typeof payload !== "object") {
    return 0;
  }
  const minutes = toFiniteNumber(
    (payload as Record<string, unknown>).minimumBookingNotice,
  );
  return minutes != null && minutes > 0 ? minutes : 0;
}

// Drop slots that are no longer bookable: anything earlier than now plus the
// minimum booking notice, evaluated in the booking timezone. Future days are
// kept untouched; only the boundary day is partially filtered. Guards against
// showing already-passed times for today (and as the session ages).
export function filterBookableSlots(
  slotsByDate: Record<string, string[]>,
  timeZone: string,
  noticeMinutes: number,
  now: Date,
): Record<string, string[]> {
  const cutoff = new Date(now.getTime() + noticeMinutes * 60_000);
  const cutoffDateKey = toDateKey(cutoff, timeZone);
  const [cutoffHoursRaw, cutoffMinutesRaw] = toTimeLabel(
    cutoff,
    timeZone,
  ).split(":");
  const cutoffHours = Number(cutoffHoursRaw);
  const cutoffMinutes = Number(cutoffMinutesRaw);
  if (Number.isNaN(cutoffHours) || Number.isNaN(cutoffMinutes)) {
    return slotsByDate;
  }
  const cutoffOfDay = cutoffHours * 60 + cutoffMinutes;

  const result: Record<string, string[]> = {};
  for (const [dateKey, times] of Object.entries(slotsByDate)) {
    if (dateKey < cutoffDateKey) {
      continue;
    }
    if (dateKey > cutoffDateKey) {
      result[dateKey] = times;
      continue;
    }
    const kept = times.filter((time) => {
      const [hoursRaw, minutesRaw] = time.split(":");
      const hours = Number(hoursRaw);
      const minutes = Number(minutesRaw);
      if (Number.isNaN(hours) || Number.isNaN(minutes)) {
        return false;
      }
      return hours * 60 + minutes >= cutoffOfDay;
    });
    if (kept.length > 0) {
      result[dateKey] = kept;
    }
  }
  return result;
}

export function findFirstAvailableDate(
  month: Date,
  slotsByDate: Record<string, string[]>,
  _timeZone: string,
  todayStart: Date,
): Date | null {
  const year = month.getFullYear();
  const monthIndex = month.getMonth();
  const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();
  const todayKey = toCalendarDateKey(todayStart);

  for (let day = 1; day <= daysInMonth; day += 1) {
    const date = new Date(year, monthIndex, day);
    const key = toCalendarDateKey(date);
    if (key < todayKey) {
      continue;
    }

    if ((slotsByDate[key] ?? []).length > 0) {
      return date;
    }
  }

  return null;
}

// --- Calendar grid (mirrors booker-calendar.tsx) ---

export function getWeekStartsOn(locale: string): number {
  try {
    const localeObj = new Intl.Locale(locale) as Intl.Locale & {
      weekInfo?: { firstDay?: number };
      getWeekInfo?: () => { firstDay?: number };
    };
    const info =
      typeof localeObj.getWeekInfo === "function"
        ? localeObj.getWeekInfo()
        : localeObj.weekInfo;
    const firstDay = info?.firstDay;
    if (typeof firstDay === "number") {
      return firstDay % 7;
    }
  } catch {
    // Fall through to the Sunday default below.
  }
  return 0;
}

function calendarStartOfMonth(date: Date): Date {
  return new Date(date.getFullYear(), date.getMonth(), 1);
}

function calendarEndOfMonth(date: Date): Date {
  return new Date(date.getFullYear(), date.getMonth() + 1, 0);
}

function calendarAddDays(date: Date, amount: number): Date {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate() + amount);
}

function calendarStartOfWeek(date: Date, weekStartsOn = 0): Date {
  const day = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  const diff = (day.getDay() - weekStartsOn + 7) % 7;
  return calendarAddDays(day, -diff);
}

function calendarEndOfWeek(date: Date, weekStartsOn = 0): Date {
  return calendarAddDays(calendarStartOfWeek(date, weekStartsOn), 6);
}

function isSameCalendarMonth(a: Date, b: Date): boolean {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth();
}

export type CalendarViewOptions = {
  weekStartsOn?: number;
  shiftWeeks?: boolean;
  startMonth?: Date;
  endMonth?: Date;
};

export function getVisibleCalendarDates(
  month: Date,
  today: Date,
  options: CalendarViewOptions = {},
): Date[] {
  const weekStartsOn = options.weekStartsOn ?? 0;
  const shiftWeeks = options.shiftWeeks ?? true;
  const firstMonth = calendarStartOfMonth(month);

  const naturalGridStart = calendarStartOfWeek(firstMonth, weekStartsOn);
  const todayStart = new Date(
    today.getFullYear(),
    today.getMonth(),
    today.getDate(),
  );
  const todayRow = Math.floor(
    Math.round(
      (todayStart.getTime() - naturalGridStart.getTime()) / 86_400_000,
    ) / 7,
  );
  const expand =
    shiftWeeks && isSameCalendarMonth(firstMonth, today) && todayRow >= 3;
  const shiftRows = expand ? Math.max(0, todayRow - 3) : 0;

  const monthStart = calendarStartOfMonth(firstMonth);
  const offset = shiftRows * 7;
  const gridStart = calendarAddDays(
    calendarStartOfWeek(monthStart, weekStartsOn),
    offset,
  );
  const gridEnd = calendarAddDays(
    calendarEndOfWeek(calendarEndOfMonth(firstMonth), weekStartsOn),
    offset,
  );

  const dates: Date[] = [];
  for (
    let cursor = gridStart;
    cursor.getTime() <= gridEnd.getTime();
    cursor = calendarAddDays(cursor, 1)
  ) {
    dates.push(cursor);
  }

  if (expand) {
    while (dates.length < 42) {
      const lastDate = dates.at(-1);
      if (!lastDate) {
        break;
      }
      dates.push(calendarAddDays(lastDate, 1));
    }
  }

  const navStart = options.startMonth
    ? calendarStartOfMonth(options.startMonth)
    : undefined;
  const navEnd = options.endMonth
    ? calendarStartOfMonth(options.endMonth)
    : undefined;
  const monthEnd = calendarEndOfMonth(firstMonth);

  return dates.filter((date) => {
    if (navStart && date < navStart) {
      return false;
    }
    if (navEnd && date > calendarEndOfMonth(navEnd)) {
      return false;
    }
    if (date < monthStart) {
      return false;
    }
    if (!expand && date > monthEnd) {
      return false;
    }
    return true;
  });
}

export function findFirstAvailableInVisibleGrid(
  month: Date,
  slotsByDate: Record<string, string[]>,
  todayStart: Date,
  options: CalendarViewOptions = {},
): Date | null {
  const todayKey = toCalendarDateKey(todayStart);
  for (const date of getVisibleCalendarDates(month, todayStart, options)) {
    const key = toCalendarDateKey(date);
    if (key < todayKey) {
      continue;
    }
    if ((slotsByDate[key] ?? []).length > 0) {
      return date;
    }
  }
  return null;
}

export function hasAvailabilityInVisibleGrid(
  month: Date,
  slotsByDate: Record<string, string[]>,
  todayStart: Date,
  options: CalendarViewOptions = {},
): boolean {
  return (
    findFirstAvailableInVisibleGrid(month, slotsByDate, todayStart, options) !=
    null
  );
}

export function pickDefaultSelectedDate(
  currentMonth: Date,
  slotsByDate: Record<string, string[]>,
  _timeZone: string,
  todayStart: Date,
  viewOptions?: CalendarViewOptions,
): Date | null {
  if (viewOptions) {
    return findFirstAvailableInVisibleGrid(
      currentMonth,
      slotsByDate,
      todayStart,
      viewOptions,
    );
  }

  return findFirstAvailableDate(
    currentMonth,
    slotsByDate,
    _timeZone,
    todayStart,
  );
}

// Earliest loaded date (today or later) that still has open slots, used to
// offer a "jump to next availability" affordance from an empty month/day.
export function findNextAvailableDate(
  slotsByDate: Record<string, string[]>,
  _timeZone: string,
  todayStart: Date,
): Date | null {
  const todayKey = toCalendarDateKey(todayStart);
  let bestKey: string | null = null;
  for (const [key, times] of Object.entries(slotsByDate)) {
    if (times.length === 0 || key < todayKey) {
      continue;
    }
    if (bestKey === null || key < bestKey) {
      bestKey = key;
    }
  }

  if (!bestKey) {
    return null;
  }

  const [yearRaw, monthRaw, dayRaw] = bestKey.split("-");
  const year = Number(yearRaw);
  const month = Number(monthRaw);
  const day = Number(dayRaw);
  if (Number.isNaN(year) || Number.isNaN(month) || Number.isNaN(day)) {
    return null;
  }
  return new Date(year, month - 1, day);
}
